```

device_container.cpp
```
void device_container::_poll_processed_queue(view_port *view, int stream_no) {
	// Ask each pipeline if there are new frames available
	rs2::processing_block frame_processor(
		[&](rs2::frameset data,        // Input frameset (from the pipeline)
			rs2::frame_source &source) // Frame pool that can allocate new frames
	{

		rs2::depth_frame filtered_frame = data.get_depth_frame();

		for (auto&& filter : view->filters) {
			if (filter.is_enabled) {
				filtered_frame = filter.filter.process(filtered_frame);
			}
		}

		auto vid_frame = view->colorize_frame(filtered_frame);
		view->message_frames.enqueue(vid_frame);
		rs2::frameset combined = source.allocate_composite_frame({ vid_frame });
		source.frame_ready(combined);

	});
	frame_processor >> view->processed_frames;
	while (_config->alive) {
		rs2::frameset frameset;
		if (view->pipe.poll_for_frames(&frameset)) {
			frame_processor.invoke(frameset);
		}
	}
}
